{
    switch (tag_) {
    case Tag::kMidi:
        return NewMidi(mojo::Clone(*data_.midi));
    case Tag::kClipboard:
        return NewClipboard(mojo::Clone(*data_.clipboard));
    case Tag::kCameraDevice:
        return NewCameraDevice(mojo::Clone(*data_.camera_device));
    case Tag::kStorageAccess:
        return NewStorageAccess(mojo::Clone(*data_.storage_access));
    }
    return nullptr;
}

template <typename T, typename std::enable_if<std::is_same<T, PermissionDescriptorExtension>::value>::type*> bool PermissionDescriptorExtension::Equals(const T& other) const
{
    if (tag_ != other.which())
        return false;

    switch (tag_) {
    case Tag::kMidi:
        return mojo::Equals(*(data_.midi), *(other.data_.midi));
    case Tag::kClipboard:
        return mojo::Equals(*(data_.clipboard), *(other.data_.clipboard));
    case Tag::kCameraDevice:
        return mojo::Equals(*(data_.camera_device), *(other.data_.camera_device));
    case Tag::kStorageAccess:
        return mojo::Equals(*(data_.storage_access), *(other.data_.storage_access));
    }

    return false;
}
